+        Value{ .u32 = request_id },
+    }) catch |err| {
+        std.debug.print("fetch-response call error: {}\n", .{err});
+        return;
+    };
+
+    // Test fetch-free
+    _ = registry.call("http", "fetch-free", &[_]Value{
+        Value{ .u32 = request_id },
+    }) catch |err| {
+        std.debug.print("fetch-free call error: {}\n", .{err});
+        return;
+    };
+}
